from openai import OpenAI
client = OpenAI()

# The model guesses based on its training data
response = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {"role": "user", "content": "What is the SLA for RetainHQ Enterprise?"}
    ]
)
print(response.choices[0].message.content)  # Likely hallucinates
